import { useState, useMemo } from "react";
import { motion } from "framer-motion";
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  BarChart,
  Bar,
  ComposedChart,
  Area,
  Brush
} from "recharts";
import {
  FiTrendingUp,
  FiTrendingDown,
  FiDollarSign,
  FiShoppingBag,
  FiUsers,
  FiDownload,
  FiRefreshCw,
  FiMaximize2,
  FiBarChart2,
  FiActivity,
  FiPieChart
} from "react-icons/fi";
import { format } from "date-fns";
const RevenueChart = ({
  data = [],
  title = "Revenue Analytics",
  subtitle = "Track your business performance",
  metrics = ["revenue", "orders"],
  period = "daily",
  height = 400,
  showControls = true,
  showBrush = true,
  showGrid = true,
  showAnimation = true,
  onMetricClick,
  onPeriodChange,
  onExport,
  onRefresh,
  isLoading = false,
  currency = "$",
  comparison = false,
  previousPeriodData = [],
  variant = "default"
}) => {
  const [chartType, setChartType] = useState("line");
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [selectedMetrics, setSelectedMetrics] = useState(metrics);
  const [hoveredPoint, setHoveredPoint] = useState(null);
  const [zoomRange, setZoomRange] = useState(null);
  const metricColors = {
    revenue: "#f97316",
    orders: "#3b82f6",
    customers: "#10b981",
    averageOrderValue: "#8b5cf6",
    profit: "#22c55e",
    costs: "#ef4444"
  };
  const metricConfig = {
    revenue: { label: "Revenue", icon: FiDollarSign, format: (val) => `${currency}${val.toLocaleString()}` },
    orders: { label: "Orders", icon: FiShoppingBag, format: (val) => val.toLocaleString() },
    customers: { label: "Customers", icon: FiUsers, format: (val) => val.toLocaleString() },
    averageOrderValue: { label: "Avg Order", icon: FiTrendingUp, format: (val) => `${currency}${val.toLocaleString()}` },
    profit: { label: "Profit", icon: FiTrendingUp, format: (val) => `${currency}${val.toLocaleString()}` },
    costs: { label: "Costs", icon: FiTrendingDown, format: (val) => `${currency}${val.toLocaleString()}` }
  };
  const processedData = useMemo(() => {
    if (!data.length) return [];
    return data.map((item, index, array) => {
      const prevItem = index > 0 ? array[index - 1] : null;
      const trends = {};
      metrics.forEach((metric) => {
        if (prevItem && prevItem[metric]) {
          const change = (item[metric] - prevItem[metric]) / prevItem[metric] * 100;
          trends[`${metric}Trend`] = change;
        }
      });
      return {
        ...item,
        ...trends,
        formattedDate: format(new Date(item._id), "MMM dd, yyyy")
      };
    });
  }, [data, metrics]);
  const summary = useMemo(() => {
    if (!processedData.length) return null;
    const total = processedData.reduce((acc, item) => ({
      revenue: acc.revenue + (item.revenue || 0),
      orders: acc.orders + (item.orders || 0),
      customers: acc.customers + (item.customers || 0),
      profit: acc.profit + (item.profit || 0),
      costs: acc.costs + (item.costs || 0)
    }), { revenue: 0, orders: 0, customers: 0, profit: 0, costs: 0 });
    const averageOrderValue = total.orders > 0 ? total.revenue / total.orders : 0;
    const firstHalf = processedData.slice(0, Math.floor(processedData.length / 2));
    const secondHalf = processedData.slice(Math.floor(processedData.length / 2));
    const firstHalfRevenue = firstHalf.reduce((sum, item) => sum + (item.revenue || 0), 0);
    const secondHalfRevenue = secondHalf.reduce((sum, item) => sum + (item.revenue || 0), 0);
    const growth = firstHalfRevenue > 0 ? (secondHalfRevenue - firstHalfRevenue) / firstHalfRevenue * 100 : 0;
    return {
      ...total,
      averageOrderValue,
      growth,
      period
    };
  }, [processedData, period]);
  const CustomTooltip = ({ active, payload, label }) => {
    if (active && payload && payload.length) {
      return <motion.div
        initial={{ opacity: 0, y: 10 }}
        animate={{ opacity: 1, y: 0 }}
        className="bg-white dark:bg-slate-800 px-4 py-3 rounded-xl
                             shadow-xl border border-slate-200 dark:border-slate-700
                             min-w-[200px]"
      >
