import { useState, useEffect, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";
import {
  FiSearch,
  FiX,
  FiFilter,
  FiClock,
  FiTrendingUp,
  FiMic,
  FiCamera,
  FiLoader
} from "react-icons/fi";
const SearchBar = ({
  onSearch,
  onSuggestionClick,
  onFilterChange,
  placeholder = "Search...",
  initialValue = "",
  suggestions = [],
  recentSearches = [],
  trendingSearches = [],
  popularCategories = [],
  filters = [],
  showFilters = true,
  showVoiceSearch = false,
  showImageSearch = false,
  autoFocus = false,
  debounceMs = 300,
  isLoading = false,
  variant = "default",
  size = "md",
  theme = "auto",
  className = "",
  onFocus,
  onBlur,
  onClear
}) => {
  const [query, setQuery] = useState(initialValue);
  const [isFocused, setIsFocused] = useState(false);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [showFilterPanel, setShowFilterPanel] = useState(false);
  const [selectedFilters, setSelectedFilters] = useState({});
  const [activeSuggestionIndex, setActiveSuggestionIndex] = useState(-1);
  const [isVoiceSearchActive, setIsVoiceSearchActive] = useState(false);
  const [recentSearchesList, setRecentSearchesList] = useState(recentSearches);
  const inputRef = useRef(null);
  const suggestionsRef = useRef(null);
  const filterRef = useRef(null);
  const debounceTimerRef = useRef();
  useEffect(() => {
    const saved = localStorage.getItem("recentSearches");
    if (saved) {
      setRecentSearchesList(JSON.parse(saved));
    }
  }, []);
  useEffect(() => {
    if (debounceTimerRef.current) {
      clearTimeout(debounceTimerRef.current);
    }
    if (query.length >= 2) {
      debounceTimerRef.current = setTimeout(() => {
        onSearch(query, selectedFilters);
      }, debounceMs);
    }
    return () => {
      if (debounceTimerRef.current) {
        clearTimeout(debounceTimerRef.current);
      }
    };
  }, [query, selectedFilters, debounceMs, onSearch]);
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (inputRef.current && !inputRef.current.contains(event.target) && suggestionsRef.current && !suggestionsRef.current.contains(event.target) && filterRef.current && !filterRef.current.contains(event.target)) {
        setIsFocused(false);
        setShowSuggestions(false);
        setShowFilterPanel(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);
  const handleKeyDown = (e) => {
    const suggestionsList = getAllSuggestions();
    switch (e.key) {
      case "ArrowDown":
        e.preventDefault();
        setActiveSuggestionIndex(
          (prev) => prev < suggestionsList.length - 1 ? prev + 1 : prev
        );
        break;
      case "ArrowUp":
        e.preventDefault();
        setActiveSuggestionIndex((prev) => prev > -1 ? prev - 1 : -1);
        break;
      case "Enter":
        if (activeSuggestionIndex >= 0) {
          e.preventDefault();
          handleSuggestionClick(suggestionsList[activeSuggestionIndex]);
        }
        break;
      case "Escape":
        setShowSuggestions(false);
        setShowFilterPanel(false);
        inputRef.current?.blur();
        break;
      case "Tab":
        setShowSuggestions(false);
        break;
    }
  };
  useEffect(() => {
    if (activeSuggestionIndex >= 0 && suggestionsRef.current) {
      const activeElement = suggestionsRef.current.children[activeSuggestionIndex];
      activeElement?.scrollIntoView({ block: "nearest" });
    }
  }, [activeSuggestionIndex]);
  const handleSubmit = (e) => {
    e.preventDefault();
    if (query.trim()) {
      const updatedRecent = [query, ...recentSearchesList.filter((s) => s !== query)].slice(0, 5);
      setRecentSearchesList(updatedRecent);
      localStorage.setItem("recentSearches", JSON.stringify(updatedRecent));
      onSearch(query, selectedFilters);
      setShowSuggestions(false);
      setIsFocused(false);
    }
  };
  const handleClear = () => {
    setQuery("");
    setActiveSuggestionIndex(-1);
    onClear?.();
    inputRef.current?.focus();
  };
  const handleSuggestionClick = (suggestion) => {
    const suggestionText = typeof suggestion === "string" ? suggestion : suggestion.text;
    setQuery(suggestionText);
    onSearch(suggestionText, selectedFilters);
    onSuggestionClick?.(typeof suggestion === "string" ? { id: suggestionText, text: suggestionText } : suggestion);
    setShowSuggestions(false);
    setIsFocused(false);
  };
  const handleFilterChange = (filterId, value) => {
    const newFilters = { ...selectedFilters, [filterId]: value };
    setSelectedFilters(newFilters);
    onFilterChange?.(newFilters);
  };
  const handleVoiceSearch = () => {
    if ("webkitSpeechRecognition" in window || "SpeechRecognition" in window) {
      setIsVoiceSearchActive(true);
      setTimeout(() => setIsVoiceSearchActive(false), 2e3);
    } else {
      alert("Voice search is not supported in your browser");
    }
  };
  const getAllSuggestions = () => {
    const all = [];
    if (recentSearchesList.length > 0 && query.length === 0) {
      all.push(...recentSearchesList);
    }
    if (trendingSearches.length > 0 && query.length === 0) {
      all.push(...trendingSearches);
    }
    if (suggestions.length > 0) {
      all.push(...suggestions);
    }
    return all;
  };
  const sizeClasses = {
    sm: {
      container: "h-10",
      input: "text-sm pl-10 pr-20",
      icon: "w-4 h-4",
      button: "px-3 py-1.5 text-sm"
    },
    md: {
      container: "h-12",
      input: "text-base pl-12 pr-24",
      icon: "w-5 h-5",
      button: "px-4 py-2 text-base"
    },
    lg: {
      container: "h-14",
      input: "text-lg pl-14 pr-28",
      icon: "w-6 h-6",
      button: "px-5 py-2.5 text-lg"
    }
  };
  const variantClasses = {
    default: "bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700",
    hero: "bg-white/90 dark:bg-slate-800/90 backdrop-blur-md border-2 border-orange-500/20 shadow-xl",
    compact: "bg-slate-100 dark:bg-slate-800 border border-transparent",
    minimal: "bg-transparent border-b border-slate-200 dark:border-slate-700 rounded-none"
  };
  return <div className={`relative ${className}`}>
            {
    /* Search Form */
  }
            <form
    onSubmit={handleSubmit}
    className={`
                    relative flex items-center rounded-xl
                    transition-all duration-200
                    ${sizeClasses[size].container}
                    ${variantClasses[variant]}
                    ${isFocused ? "ring-2 ring-orange-500/20 border-orange-500" : ""}
                `}
  >
                {
    /* Search Icon */
  }
                <div className="absolute left-3 text-slate-400">
                    {isLoading ? <FiLoader className={`${sizeClasses[size].icon} animate-spin`} /> : <FiSearch className={sizeClasses[size].icon} />}
                </div>

                {
    /* Input */
  }
                <input
    ref={inputRef}
    type="text"
    value={query}
    onChange={(e) => {
      setQuery(e.target.value);
      setShowSuggestions(true);
      setActiveSuggestionIndex(-1);
    }}
    onFocus={() => {
      setIsFocused(true);
      setShowSuggestions(true);
      onFocus?.();
    }}
    onBlur={() => {
      onBlur?.();
    }}
    onKeyDown={handleKeyDown}
    placeholder={placeholder}
    autoFocus={autoFocus}
    className={`
                        w-full h-full bg-transparent
                        ${sizeClasses[size].input}
                        text-slate-900 dark:text-white
                        placeholder:text-slate-400 dark:placeholder:text-slate-500
                        outline-none
                    `}
  />

                {
    /* Right Side Actions */
  }
                <div className="absolute right-2 flex items-center gap-1">
                    {
    /* Filter Button */
  }
                    {showFilters && filters.length > 0 && <button
    type="button"
    onClick={() => setShowFilterPanel(!showFilterPanel)}
    className={`
                                p-1.5 rounded-lg transition-colors
                                ${Object.keys(selectedFilters).length > 0 ? "text-orange-500 bg-orange-50 dark:bg-orange-900/20" : "text-slate-400 hover:text-orange-500 hover:bg-slate-100 dark:hover:bg-slate-700"}
                            `}
  >
                            <FiFilter className={sizeClasses[size].icon} />
                        </button>}

                    {
    /* Voice Search */
  }
                    {showVoiceSearch && <button
    type="button"
    onClick={handleVoiceSearch}
    className={`
                                p-1.5 rounded-lg transition-colors
                                ${isVoiceSearchActive ? "text-red-500 bg-red-50 dark:bg-red-900/20 animate-pulse" : "text-slate-400 hover:text-orange-500 hover:bg-slate-100 dark:hover:bg-slate-700"}
                            `}
  >
                            <FiMic className={sizeClasses[size].icon} />
                        </button>}

                    {
    /* Image Search */
  }
                    {showImageSearch && <button
    type="button"
    className="p-1.5 text-slate-400 hover:text-orange-500
                                     hover:bg-slate-100 dark:hover:bg-slate-700
                                     rounded-lg transition-colors"
  >
                            <FiCamera className={sizeClasses[size].icon} />
                        </button>}

                    {
    /* Clear Button */
  }
                    {query && <button
    type="button"
    onClick={handleClear}
    className="p-1.5 text-slate-400 hover:text-orange-500
                                     hover:bg-slate-100 dark:hover:bg-slate-700
                                     rounded-lg transition-colors"
  >
                            <FiX className={sizeClasses[size].icon} />
                        </button>}

                    {
    /* Search Button */
  }
                    <button
    type="submit"
    className="px-3 py-1.5 bg-orange-500 hover:bg-orange-600
                                 text-white rounded-lg transition-colors
                                 text-sm font-medium"
  >
                        Search
                    </button>
                </div>
            </form>

            {
    /* Suggestions Dropdown */
  }
            <AnimatePresence>
                {isFocused && showSuggestions && getAllSuggestions().length > 0 && <motion.div
    ref={suggestionsRef}
    initial={{ opacity: 0, y: -10 }}
    animate={{ opacity: 1, y: 0 }}
    exit={{ opacity: 0, y: -10 }}
    transition={{ duration: 0.2 }}
    className="absolute z-50 w-full mt-2 bg-white dark:bg-slate-800
                                 rounded-xl shadow-xl border border-slate-200 dark:border-slate-700
                                 max-h-96 overflow-y-auto"
  >
                        {
    /* Recent Searches */
  }
                        {recentSearchesList.length > 0 && query.length === 0 && <div className="p-2">
